const res = await fetch(
  "https://transfer-sandbox.payven.com.tr/api/v1/transfers/8e3f5c12-9a7b-4c8d-bc4e-2c963f66afa6",
  {
    method: "GET",
    headers: {
      Authorization: `Bearer ${accessToken}`,
      "Content-Type": "application/json",
    },
  },
);
const data = await res.json();

import httpx
res = httpx.get(
    "https://transfer-sandbox.payven.com.tr/api/v1/transfers/8e3f5c12-9a7b-4c8d-bc4e-2c963f66afa6",
    headers={
        "Authorization": f"Bearer {access_token}",
    },
)
data = res.json()

var req = new HttpRequestMessage(HttpMethod.Get, "https://transfer-sandbox.payven.com.tr/api/v1/transfers/8e3f5c12-9a7b-4c8d-bc4e-2c963f66afa6");
req.Headers.Authorization = new AuthenticationHeaderValue("Bearer", accessToken);
var resp = await http.SendAsync(req);

$ch = curl_init("https://transfer-sandbox.payven.com.tr/api/v1/transfers/8e3f5c12-9a7b-4c8d-bc4e-2c963f66afa6");
curl_setopt_array($ch, [
  CURLOPT_CUSTOMREQUEST => "GET",
  CURLOPT_RETURNTRANSFER => true,
  CURLOPT_HTTPHEADER => [
    "Authorization: Bearer $accessToken",
  ],
]);
$data = json_decode(curl_exec($ch), true);

const res = await fetch(
  "https://transfer-sandbox.payven.com.tr/api/v1/transfers/bulk/create",
