      Authorization: `Bearer ${accessToken}`,
      "Idempotency-Key": "order-1001",
      "Content-Type": "application/json",
    },
    body: JSON.stringify({ /* payload */ }),
  },
);
const data = await res.json();

import httpx
res = httpx.post(
    "https://transfer-sandbox.payven.com.tr/api/v1/transfers/bulk/create",
    headers={
        "Authorization": f"Bearer {access_token}",
        "Idempotency-Key": "order-1001",
    },
    json={ ... },
)
data = res.json()

var req = new HttpRequestMessage(HttpMethod.Post, "https://transfer-sandbox.payven.com.tr/api/v1/transfers/bulk/create");
req.Headers.Authorization = new AuthenticationHeaderValue("Bearer", accessToken);
req.Headers.Add("Idempotency-Key", "order-1001");
// Content = JsonContent.Create(payload);
var resp = await http.SendAsync(req);

$ch = curl_init("https://transfer-sandbox.payven.com.tr/api/v1/transfers/bulk/create");
curl_setopt_array($ch, [
  CURLOPT_CUSTOMREQUEST => "POST",
  CURLOPT_RETURNTRANSFER => true,
  CURLOPT_HTTPHEADER => [
    "Authorization: Bearer $accessToken",
    "Idempotency-Key: order-1001",
  ],
  CURLOPT_POSTFIELDS => json_encode(\$payload),
]);
$data = json_decode(curl_exec($ch), true);
